use std::convert::identity;

// Experimental helper: report the size of a closure's captured environment.
// F is the concrete (anonymous) closure type; size_of::<F>() counts every captured variable.
fn closure_size<F: FnOnce()>(_: &F) -> usize {
    std::mem::size_of::<F>()
}

const DATA_WORDS: usize = 3;
type Data = [usize; DATA_WORDS];

fn main() {
    // Small closure — captures one usize word.
    let fired = Cell::new(false);
    let a = [0usize; 1];
    let f_small = move || {
        let _ = identity(a);
        fired.set(true);
