    let size_small = closure_size(&f_small);

    // Big closure — captures ten usize words.
    let fired = Cell::new(false);
    let a = [0usize; 10];
    let f_big = move || {
        let _ = identity(a);
        fired.set(true);
    };
    let size_big = closure_size(&f_big);

    let inline_capacity = std::mem::size_of::<Data>();

    println!("small closure size = {} bytes", size_small);
    println!("big   closure size = {} bytes", size_big);
    println!("inline capacity    = {} bytes (3 usize)", inline_capacity);

    if size_small <= inline_capacity {
        println!("=> small closure goes INLINE");
    }
    if size_big > inline_capacity {
        println!("=> big   closure goes HEAP (boxed)");
    }
}
```

